// Lever public job posting API — no auth required.
// API: GET https://api.lever.co/v0/postings/{slug}?mode=json
// Add company slugs here. Find slugs at: https://jobs.lever.co/{slug}
const companies = [
  'contentful',
  'netlify',
  'elastic',
  'shopify',
  'auth0',
  'twilio',
  'heap',
  'bitrise',
  'miro',
  'hotjar',
  'personio',
  'pleo',
  'deliveroo',
  'babylon',
  'transfer-wise',
  'bereal',
];
return companies.map(slug => ({ json: { slug } }));

// Lever response is a JSON array at root or wrapped in {data:[]}
// NOTE: Lever's API does not include a company field in posting objects.
// Use the slug from the Companies node as the company name.
function stripHtml(html) {
  return (html || '').replace(/<[^>]*>/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ').replace(/&#39;/g, "'").replace(/&quot;/g, '"').replace(/\s+/g, ' ').trim();
}
const companySlug = $('Companies').item.json.slug || '';
const raw = $json;
const jobs = Array.isArray(raw) ? raw : (Array.isArray(raw.data) ? raw.data : []);
return jobs.map(j => {
  const workplaceType = (j.workplaceType || '').toLowerCase();
  const loc = (j.categories && j.categories.location) || '';
  const isRemote = workplaceType === 'remote' || loc.toLowerCase().includes('remote');
  // Build description from lists
  const lists = (j.lists || []).map(l => l.content || '').join(' ');
  const descText = stripHtml((j.descriptionPlain || j.description || '') + ' ' + lists).slice(0, 8000);
  return {
    json: {
      source: 'lever',
      external_id: String(j.id ?? ''),
      company: companySlug,
      title: (j.text || j.title || '').trim(),
      location: loc,
      remote: isRemote ? 'remote' : 'unknown',
      url: j.hostedUrl || j.applyUrl || '',
      description: descText,
      posted_at: j.createdAt ? new Date(j.createdAt).toISOString() : null,
    }
  };
});

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}
return items.map(({ json }) => {
  const base = [json.source, json.external_id, json.company, json.title, json.url].join('|');
  return { json: { ...json, content_hash: simpleHash(base) } };
});
